/**
 * @summary List posts for a client
 */
export const getListPostsUrl = (clientId: string, params?: ListPostsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/clients/${clientId}/posts?${stringifiedParams}`
    : `/api/clients/${clientId}/posts`;
};

export const listPosts = async (
  clientId: string,
  params?: ListPostsParams,
  options?: RequestInit,
): Promise<Post[]> => {
  return customFetch<Post[]>(getListPostsUrl(clientId, params), {
    ...options,
    method: "GET",
  });
};

export const getListPostsQueryKey = (
  clientId: string,
  params?: ListPostsParams,
) => {
  return [
    `/api/clients/${clientId}/posts`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListPostsQueryOptions = <
  TData = Awaited<ReturnType<typeof listPosts>>,
  TError = ErrorType<unknown>,
>(
  clientId: string,
  params?: ListPostsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listPosts>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListPostsQueryKey(clientId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listPosts>>> = ({
    signal,
  }) => listPosts(clientId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!clientId,
    ...queryOptions,
  } as UseQueryOptions<Awaited<ReturnType<typeof listPosts>>, TError, TData> & {
    queryKey: QueryKey;
  };
};

export type ListPostsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listPosts>>
>;
export type ListPostsQueryError = ErrorType<unknown>;

