/**
 * @summary List images for a post
 */
export const getListPostImagesUrl = (clientId: string, postId: string) => {
  return `/api/clients/${clientId}/posts/${postId}/images`;
};

export const listPostImages = async (
  clientId: string,
  postId: string,
  options?: RequestInit,
): Promise<Image[]> => {
  return customFetch<Image[]>(getListPostImagesUrl(clientId, postId), {
    ...options,
    method: "GET",
  });
};

export const getListPostImagesQueryKey = (clientId: string, postId: string) => {
  return [`/api/clients/${clientId}/posts/${postId}/images`] as const;
};

export const getListPostImagesQueryOptions = <
  TData = Awaited<ReturnType<typeof listPostImages>>,
  TError = ErrorType<unknown>,
>(
  clientId: string,
  postId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listPostImages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListPostImagesQueryKey(clientId, postId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listPostImages>>> = ({
    signal,
  }) => listPostImages(clientId, postId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!(clientId && postId),
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listPostImages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListPostImagesQueryResult = NonNullable<
  Awaited<ReturnType<typeof listPostImages>>
>;
export type ListPostImagesQueryError = ErrorType<unknown>;

